class Solution:
    def solve(self, nums, l, r):
        if l == r:
            return False
        i = l
        j = r
        while i < j:
            if nums[i] > nums[i + 1] and nums[j] < nums[j - 1]:
                return True
            if nums[i] > nums[i + 1]:
                i += 1
            elif nums[j] < nums[j - 1]:
                j -= 1
            else:
                i += 1
                j -= 1
        return False

