#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    bool solve(vector<int>& nums, int l, int r) {
	if (l == r) return false;
	int i = l;
	int j = r;
	while (i < j) {
		if (nums[i] > nums[i + 1] && nums[j] < nums[j - 1]) return true;
		if (nums[i] > nums[i + 1]) i++;
		else if (nums[j] < nums[j - 1]) j--;
		else i++, j--;
	}
	return false;
    }
};
int main() {
	ios::sync_with_stdio(false);
	cin.tie(0);
	Solution s;
	int n;
	cin >> n;
	vector<int> nums(n);
	for (int i = 0; i < n; i++) cin >> nums[i];
	int l, r;
	cin >> l >> r;
	cout << (s.solve(nums, l, r) ? "True" : "False") << endl;
	return 0;
}
